3	namespace App\Policies;
4	
5	use App\Enums\CampaignStatus;
6	use App\Models\User;
7	use App\Models\VenueProgram;
8	
9	class VenueProgramPolicy
10	{
11	    /**
12	     * Anyone may browse venue programs.
13	     */
14	    public function viewAny(?User $user): bool
15	    {
16	        return true;
17	    }
18	
19	    /**
20	     * Anyone may view a single venue program.
21	     */
22	    public function view(?User $user, VenueProgram $program): bool
23	    {
24	        return true;
25	    }
26	
27	    /**
28	     * Only users with the programs.create permission may create.
29	     */
30	    public function create(User $user): bool
31	    {
32	        return $user->hasPermission('programs.create');
33	    }
34	
35	    /**
36	     * Only users with the programs.create permission may update.
37	     */
38	    public function update(User $user, VenueProgram $program): bool
39	    {
40	        return $user->hasPermission('programs.create');
41	    }
42	
43	    /**
44	     * Submit a draft program for review.
45	     */
46	    public function submit(User $user, VenueProgram $program): bool
47	    {
48	        return $user->hasPermission('programs.create')
49	            && $program->status === CampaignStatus::Draft;
50	    }
51	
52	    /**
53	     * Approve a program that is pending review.
54	     */
55	    public function approve(User $user, VenueProgram $program): bool
56	    {
57	        return $user->hasPermission('programs.approve')
58	            && $program->status === CampaignStatus::PendingReview;
59	    }
60	
61	    /**
62	     * Toggle visibility of a venue program.
63	     */
64	    public function toggleVisibility(User $user, VenueProgram $program): bool
65	    {
66	        return $user->hasPermission('programs.approve');
67	    }
68	}
