3	namespace App\Http\Controllers\Api\Campaign;
4	
5	use App\Enums\CampaignStatus;
6	use App\Enums\CampaignVisibility;
7	use App\Http\Controllers\Api\BaseController;
8	use App\Models\VenueProgram;
9	use Illuminate\Http\JsonResponse;
10	use Illuminate\Http\Request;
11	use Illuminate\Support\Str;
12	
13	class VenueProgramController extends BaseController
14	{
15	    /**
16	     * GET /api/programs
17	     */
18	    public function index(Request $request): JsonResponse
19	    {
20	        $query = VenueProgram::query()
21	            ->with(['timeSlots', 'creator'])
22	            ->latest();
23	
24	        // Moderators/admins can filter by any status (e.g. pending_review for approval queue)
25	        $user = $request->user();
26	        $isPrivileged = $user && ($user->hasRole('moderator') || $user->hasRole('admin'));
27	
28	        if ($isPrivileged && $request->filled('status')) {
29	            $query->where('status', $request->query('status'));
30	        } else {
31	            // Public listing: only published + online
32	            $query->where('status', CampaignStatus::Published)
33	                ->where('visibility', CampaignVisibility::Online);
34	        }
35	
36	        if ($request->filled('search')) {
37	            $query->where('title', 'ilike', '%' . $request->query('search') . '%');
38	        }
39	
40	        return $this->paginated($query);
41	    }
42	
43	    /**
44	     * GET /api/programs/{program}
45	     */
46	    public function show(Request $request, VenueProgram $program): JsonResponse
47	    {
48	        // Public users can only view published + online programs
49	        $user = $request->user();
50	        $isPrivileged = $user && ($user->hasRole('moderator') || $user->hasRole('admin') || $user->id === $program->created_by);
51	
52	        if (! $isPrivileged) {
53	            if ($program->status !== CampaignStatus::Published || $program->visibility !== CampaignVisibility::Online) {
54	                return $this->error('Resource not found.', 404);
55	            }
56	        }
57	
58	        $program->load('timeSlots');
59	
60	        return $this->success($program);
61	    }
62	
63	    /**
64	     * POST /api/programs
65	     */
66	    public function store(Request $request): JsonResponse
67	    {
68	        $this->authorize('create', VenueProgram::class);
69	
70	        $request->validate([
71	            'title' => 'required|string|max:255',
72	            'description' => 'required|string',
73	            'location' => 'sometimes|string|max:255',
74	        ]);
75	
76	        $program = VenueProgram::create([
77	            'title' => $request->input('title'),
78	            'slug' => Str::slug($request->input('title')) . '-' . Str::random(6),
79	            'description' => $request->input('description'),
80	            'location' => $request->input('location'),
81	            'status' => CampaignStatus::Draft,
82	            'visibility' => CampaignVisibility::Offline,
83	            'created_by' => $request->user()->id,
84	        ]);
85	
86	        return $this->success($program, 201);
87	    }
88	
89	    /**
90	     * PUT /api/programs/{program}
91	     */
92	    public function update(Request $request, VenueProgram $program): JsonResponse
93	    {
94	        $this->authorize('update', $program);
95	
96	        $request->validate([
97	            'title' => 'sometimes|string|max:255',
98	            'description' => 'sometimes|string',
99	            'location' => 'sometimes|string|max:255',
100	        ]);
101	
102	        $program->update($request->only(['title', 'description', 'location']));
103	
104	        return $this->success($program->refresh());
105	    }
106	
107	    /**
108	     * POST /api/programs/{program}/submit
109	     */
110	    public function submit(VenueProgram $program): JsonResponse
111	    {
112	        $this->authorize('submit', $program);
113	
114	        $program->update(['status' => CampaignStatus::PendingReview]);
115	
116	        return $this->success($program->refresh());
117	    }
118	
119	    /**
120	     * POST /api/programs/{program}/approve
121	     */
122	    public function approve(Request $request, VenueProgram $program): JsonResponse
123	    {
124	        $this->authorize('approve', $program);
125	
126	        $program->update([
127	            'status' => CampaignStatus::Published,
128	            'visibility' => CampaignVisibility::Online,
129	            'reviewed_by' => $request->user()->id,
130	            'reviewed_at' => now(),
131	        ]);
132	
133	        return $this->success($program->refresh());
134	    }
135	
136	    /**
137	     * POST /api/programs/{program}/reject
138	     */
139	    public function reject(Request $request, VenueProgram $program): JsonResponse
140	    {
141	        $this->authorize('reject', $program);
142	
143	        $request->validate([
144	            'notes' => 'required|string',
145	        ]);
146	
147	        $program->update([
148	            'status' => CampaignStatus::Draft,
149	            'reviewed_by' => $request->user()->id,
150	            'reviewed_at' => now(),
151	            'review_notes' => $request->input('notes'),
152	        ]);
153	
154	        return $this->success($program->refresh());
155	    }
156	
157	    /**
158	     * POST /api/programs/{program}/visibility
159	     */
160	    public function visibility(Request $request, VenueProgram $program): JsonResponse
161	    {
162	        $this->authorize('toggleVisibility', $program);
163	
164	        $request->validate([
165	            'visibility' => 'required|string|in:online,offline',
166	        ]);
167	
168	        $program->update([
169	            'visibility' => CampaignVisibility::from($request->input('visibility')),
170	        ]);
171	
172	        return $this->success($program->refresh());
173	    }
174	}
