3	namespace App\Console\Commands;
4	
5	use App\Enums\OrderStatus;
6	use App\Enums\OrderType;
7	use App\Models\BusinessParameter;
8	use App\Models\Notification;
9	use App\Models\Order;
10	use App\Models\TimeSlot;
11	use App\Services\Notification\NotificationService;
12	use Illuminate\Console\Command;
13	
14	class SendBookingReminders extends Command
15	{
16	    protected $signature = 'bookings:send-reminders';
17	
18	    protected $description = 'Send booking reminder notifications for upcoming time slots';
19	
20	    private const DEFAULT_LEAD_HOURS = '24,2';
21	
22	    private const REMINDER_TEMPLATE_KEY = 'booking.reminder';
23	
24	    public function handle(NotificationService $notificationService): int
25	    {
26	        $leadHoursParam = BusinessParameter::where('key', 'reminder_lead_hours')->first();
27	        $leadHoursString = $leadHoursParam ? $leadHoursParam->getTypedValue() : self::DEFAULT_LEAD_HOURS;
28	
29	        $leadHours = array_map('trim', explode(',', $leadHoursString));
30	        $leadHours = array_filter($leadHours, fn ($h) => is_numeric($h));
31	
32	        $totalSent = 0;
33	
34	        foreach ($leadHours as $hours) {
35	            $hours = (float) $hours;
36	
37	            $windowStart = now()->addMinutes((int) ($hours * 60) - 7);
38	            $windowEnd = now()->addMinutes((int) ($hours * 60) + 8);
39	
40	            $timeSlots = TimeSlot::query()
41	                ->where('starts_at', '>=', $windowStart)
42	                ->where('starts_at', '<=', $windowEnd)
43	                ->get();
44	
45	            if ($timeSlots->isEmpty()) {
46	                continue;
47	            }
48	
49	            $orders = Order::query()
50	                ->whereIn('time_slot_id', $timeSlots->pluck('id'))
51	                ->where('status', OrderStatus::Confirmed)
52	                ->where('order_type', OrderType::Reservation)
53	                ->with(['user', 'timeSlot'])
54	                ->get();
55	
56	            foreach ($orders as $order) {
57	                // Check if a reminder notification was already sent for this order and lead time
58	                $alreadySent = Notification::query()
59	                    ->where('user_id', $order->user_id)
60	                    ->where('data->order_id', $order->id)
61	                    ->where('data->lead_hours', $hours)
62	                    ->exists();
63	
64	                if ($alreadySent) {
65	                    continue;
66	                }
67	
68	                $notificationService->dispatch($order->user, self::REMINDER_TEMPLATE_KEY, [
69	                    'order_id' => $order->id,
70	                    'confirmation_number' => $order->confirmation_number,
71	                    'starts_at' => $order->timeSlot->starts_at->toIso8601String(),
72	                    'lead_hours' => $hours,
73	                ]);
74	
75	                $totalSent++;
76	            }
77	        }
78	
79	        $this->info("Sent {$totalSent} booking reminder(s).");
80	
81	        return self::SUCCESS;
82	    }
83	}
