3	namespace App\Livewire\Campaign;
4	
5	use App\Services\ApiClient;
6	use Illuminate\Contracts\View\View;
7	use Livewire\Attributes\Layout;
8	use Livewire\Component;
9	use RuntimeException;
10	
11	#[Layout('layouts.app')]
12	class CampaignDetail extends Component
13	{
14	    protected ApiClient $apiClient;
15	
16	    public int $campaignId;
17	    public array $campaign = [];
18	    public int $selectedTierId = 0;
19	
20	    public function boot(ApiClient $apiClient): void
21	    {
22	        $this->apiClient = $apiClient;
23	    }
24	
25	    public function mount(int $campaignId): void
26	    {
27	        $this->campaignId = $campaignId;
28	        $this->loadCampaign();
29	    }
30	
31	    public function loadCampaign(): void
32	    {
33	        try {
34	            $response = $this->apiClient->get("/api/campaigns/{$this->campaignId}");
35	            $this->campaign = $response['campaign'] ?? $response;
36	        } catch (RuntimeException $e) {
37	            session()->flash('error', $e->getMessage());
38	        }
39	    }
40	
41	    public function refreshCampaign(): void
42	    {
43	        $this->loadCampaign();
44	    }
45	
46	    public function approve(): void
47	    {
48	        try {
49	            $this->apiClient->post("/api/campaigns/{$this->campaignId}/approve");
50	            session()->flash('success', 'Campaign approved successfully.');
51	            $this->loadCampaign();
52	        } catch (RuntimeException $e) {
53	            session()->flash('error', $e->getMessage());
54	        }
55	    }
56	
57	    public function reject(string $reason): void
58	    {
59	        if (trim($reason) === '') {
60	            $this->addError('rejectReason', 'A rejection reason is required.');
61	            return;
62	        }
63	
64	        try {
65	            $this->apiClient->post("/api/campaigns/{$this->campaignId}/reject", [
66	                'notes' => $reason,
67	            ]);
68	            session()->flash('success', 'Campaign rejected.');
69	            $this->loadCampaign();
70	        } catch (RuntimeException $e) {
71	            session()->flash('error', $e->getMessage());
72	        }
73	    }
74	
75	    public function toggleVisibility(): void
76	    {
77	        $currentVisibility = $this->campaign['visibility'] ?? 'offline';
78	        $newVisibility = $currentVisibility === 'online' ? 'offline' : 'online';
79	
80	        try {
81	            $this->apiClient->post("/api/campaigns/{$this->campaignId}/visibility", [
82	                'visibility' => $newVisibility,
83	            ]);
84	            session()->flash('success', "Campaign visibility changed to {$newVisibility}.");
85	            $this->loadCampaign();
86	        } catch (RuntimeException $e) {
87	            session()->flash('error', $e->getMessage());
88	        }
89	    }
90	
91	    public function closeCampaign(): void
92	    {
93	        try {
94	            $this->apiClient->post("/api/campaigns/{$this->campaignId}/close");
95	            session()->flash('success', 'Campaign closed.');
96	            $this->loadCampaign();
97	        } catch (RuntimeException $e) {
98	            session()->flash('error', $e->getMessage());
99	        }
100	    }
101	
102	    public function submitForReview(): void
103	    {
104	        try {
105	            $this->apiClient->post("/api/campaigns/{$this->campaignId}/submit");
106	            session()->flash('success', 'Campaign submitted for review.');
107	            $this->loadCampaign();
108	        } catch (RuntimeException $e) {
109	            session()->flash('error', $e->getMessage());
110	        }
111	    }
112	
113	    public function contribute(int $tierId): void
114	    {
115	        try {
116	            $response = $this->apiClient->post('/api/orders', [
117	                'campaign_id' => $this->campaignId,
118	                'reward_tier_id' => $tierId,
119	                'request_key' => 'contrib-' . $this->campaignId . '-' . $tierId . '-' . uniqid(),
120	            ]);
121	
122	            $orderId = $response['id'] ?? ($response['data']['id'] ?? null);
123	            if ($orderId) {
124	                $this->redirect(route('orders.detail', ['orderId' => $orderId]));
125	                return;
126	            }
127	
128	            session()->flash('success', 'Contribution order created successfully.');
129	            $this->loadCampaign();
130	        } catch (\RuntimeException $e) {
131	            session()->flash('error', $e->getMessage());
132	        }
133	    }
