10	
11	class IdempotencyGuard
12	{
13	    private const CACHE_PREFIX = 'idempotency:';
14	
15	    private const CACHE_TTL_MINUTES = 10;
16	
17	    public function handle(Request $request, Closure $next): Response
18	    {
19	        $idempotencyKey = $request->header('X-Idempotency-Key');
20	
21	        if (! $idempotencyKey) {
22	            return new JsonResponse([
23	                'message' => 'The X-Idempotency-Key header is required.',
24	            ], 422);
25	        }
26	
27	        $userId = $request->user()?->id ?? 'anonymous';
28	        $cacheKey = self::CACHE_PREFIX . $userId . ':' . $request->method() . ':' . $request->path() . ':' . $idempotencyKey;
29	
30	        $cached = Cache::get($cacheKey);
31	
32	        if ($cached !== null) {
33	            return new JsonResponse(
34	                $cached['data'],
35	                $cached['status'],
36	                array_merge($cached['headers'] ?? [], ['X-Idempotent-Replayed' => 'true']),
37	            );
38	        }
39	
40	        /** @var Response $response */
41	        $response = $next($request);
42	
43	        if ($response instanceof JsonResponse) {
44	            Cache::put($cacheKey, [
45	                'data' => $response->getData(true),
46	                'status' => $response->getStatusCode(),
47	                'headers' => [],
48	            ], now()->addMinutes(self::CACHE_TTL_MINUTES));
49	        }
50	
51	        return $response;
52	    }
53	}
