5	use Illuminate\Support\Facades\Http;
6	use Illuminate\Support\Facades\Session;
7	use Illuminate\Http\Client\Response;
8	use RuntimeException;
9	
10	class ApiClient
11	{
12	    private string $baseUrl;
13	
14	    public function __construct()
15	    {
16	        $this->baseUrl = rtrim(config('services.backend.url', 'http://backend-nginx:80'), '/');
17	    }
18	
19	    public function get(string $path, array $query = []): array
20	    {
21	        $response = $this->request()->get($this->baseUrl . $path, $query);
22	        return $this->handleResponse($response);
23	    }
24	
25	    public function post(string $path, array $data = [], array $headers = []): array
26	    {
27	        $request = $this->request();
28	        if (!empty($headers)) {
29	            $request = $request->withHeaders($headers);
30	        }
31	        $response = $request->post($this->baseUrl . $path, $data);
32	        return $this->handleResponse($response);
33	    }
34	
35	    public function put(string $path, array $data = []): array
36	    {
37	        $response = $this->request()->put($this->baseUrl . $path, $data);
38	        return $this->handleResponse($response);
39	    }
40	
41	    public function delete(string $path): array
42	    {
43	        $response = $this->request()->delete($this->baseUrl . $path);
44	        return $this->handleResponse($response);
45	    }
46	
47	    public function postWithFile(string $path, array $data = [], string $fileKey = 'attachment', $file = null): array
48	    {
49	        $request = $this->request();
50	
51	        if ($file) {
52	            $request = $request->attach(
53	                $fileKey,
54	                file_get_contents($file->getRealPath()),
55	                $file->getClientOriginalName()
56	            );
57	        }
58	
59	        $response = $request->post($this->baseUrl . $path, $data);
60	        return $this->handleResponse($response);
61	    }
62	
63	    public function login(string $username, string $password): array
64	    {
65	        $response = Http::acceptJson()
66	            ->post($this->baseUrl . '/api/auth/login', [
67	                'username' => $username,
68	                'password' => $password,
69	            ]);
70	
71	        return $this->handleResponse($response);
72	    }
73	
74	    public function logout(): void
75	    {
76	        try {
77	            $this->post('/api/auth/logout');
78	        } catch (RuntimeException $e) {
79	            // Ignore logout errors
80	        }
81	    }
82	
83	    private function request(): \Illuminate\Http\Client\PendingRequest
84	    {
85	        $request = Http::acceptJson()->timeout(30);
86	        $token = Session::get('api_token');
87	        if ($token) {
88	            $request = $request->withToken($token);
89	        }
90	        return $request;
91	    }
92	
93	    private function handleResponse(Response $response): array
94	    {
95	        if ($response->successful()) {
96	            return $response->json() ?? [];
97	        }
98	
99	        if ($response->status() === 401) {
100	            Session::forget(['api_token', 'api_user']);
101	            throw new RuntimeException('Session expired. Please log in again.', 401);
102	        }
103	
104	        $body = $response->json();
105	        $message = $body['msg'] ?? $body['message'] ?? 'API request failed';
106	        throw new RuntimeException($message, $response->status());
107	    }
108	}
