3	namespace App\Livewire\Booking;
4	
5	use App\Services\ApiClient;
6	use Illuminate\Contracts\View\View;
7	use Livewire\Attributes\Layout;
8	use Livewire\Component;
9	use RuntimeException;
10	
11	#[Layout('layouts.app')]
12	class SeatMap extends Component
13	{
14	    protected ApiClient $apiClient;
15	
16	    public int $timeSlotId;
17	    public array $timeSlot = [];
18	    public int $availableSeats = 0;
19	    public int $totalCapacity = 0;
20	    public int $seatsBooked = 0;
21	    public int $lockedByOthers = 0;
22	    public ?array $myLock = null;
23	    public int $quantity = 1;
24	    public string $confirmationNumber = '';
25	    public string $errorMessage = '';
26	
27	    public function boot(ApiClient $apiClient): void
28	    {
29	        $this->apiClient = $apiClient;
30	    }
31	
32	    public function mount(int $timeSlotId): void
33	    {
34	        $this->timeSlotId = $timeSlotId;
35	        $this->refreshAvailability();
36	    }
37	
38	    public function refreshAvailability(): void
39	    {
40	        try {
41	            $response = $this->apiClient->get("/api/time-slots/{$this->timeSlotId}");
42	
43	            $this->timeSlot = $response['time_slot'] ?? [];
44	            $this->availableSeats = $response['available_seats'] ?? 0;
45	            $this->totalCapacity = $this->timeSlot['seat_capacity'] ?? 0;
46	            $this->seatsBooked = $this->timeSlot['seats_booked'] ?? 0;
47	
48	            $locks = $response['locks'] ?? [];
49	
50	            // Calculate locks by others and check for my lock
51	            $this->lockedByOthers = 0;
52	            $foundMyLock = false;
53	
54	            foreach ($locks as $lock) {
55	                if (!empty($lock['held_by_me'])) {
56	                    $this->myLock = [
57	                        'id' => $lock['id'],
58	                        'quantity' => $lock['quantity'],
59	                        'locked_until' => $lock['locked_until'],
60	                    ];
61	                    $foundMyLock = true;
62	                } elseif (!empty($lock['held_by_other'])) {
63	                    $this->lockedByOthers += $lock['quantity'];
64	                }
65	            }
66	
67	            // If we had a lock but it's no longer in the active list, clear it
68	            if ($this->myLock && !$foundMyLock) {
69	                $this->myLock = null;
70	            }
71	        } catch (RuntimeException $e) {
72	            $this->errorMessage = $e->getMessage();
73	        }
74	    }
75	
76	    public function lockSeats(): void
77	    {
78	        $this->errorMessage = '';
79	
80	        if ($this->quantity < 1) {
81	            $this->errorMessage = 'Quantity must be at least 1.';
82	            return;
83	        }
84	
85	        try {
86	            $response = $this->apiClient->post("/api/time-slots/{$this->timeSlotId}/lock", [
87	                'quantity' => $this->quantity,
88	            ]);
89	
90	            $lock = $response['lock'] ?? [];
91	            $this->myLock = [
92	                'id' => $lock['id'],
93	                'quantity' => $lock['quantity'],
94	                'locked_until' => $lock['locked_until'],
95	            ];
96	
97	            $this->refreshAvailability();
98	        } catch (RuntimeException $e) {
99	            $this->errorMessage = $e->getMessage();
100	        }
101	    }
102	
103	    public function releaseLock(): void
104	    {
105	        $this->errorMessage = '';
106	
107	        if (!$this->myLock) {
108	            return;
109	        }
110	
111	        try {
112	            $lockId = $this->myLock['id'];
113	            $this->apiClient->delete("/api/seat-locks/{$lockId}");
114	        } catch (RuntimeException $e) {
115	            // Lock may have already expired
116	        }
117	
118	        $this->myLock = null;
119	        $this->refreshAvailability();
120	    }
121	
122	    public function confirmBooking(): mixed
123	    {
124	        $this->errorMessage = '';
125	
126	        if (!$this->myLock) {
127	            $this->errorMessage = 'You must lock seats before confirming.';
128	            return null;
129	        }
130	
131	        try {
132	            $lockId = $this->myLock['id'];
133	            $idempotencyKey = 'confirm-' . $lockId . '-' . session()->getId();
134	            $response = $this->apiClient->post("/api/seat-locks/{$lockId}/confirm", [], [
135	                'X-Idempotency-Key' => $idempotencyKey,
136	            ]);
137	
138	            $this->confirmationNumber = $response['confirmation_number'] ?? '';
139	            $orderId = $response['order']['id'] ?? null;
140	            $this->myLock = null;
141	
142	            if ($orderId) {
143	                return $this->redirect(
144	                    route('orders.detail', ['orderId' => $orderId]),
145	                    navigate: true,
146	                );
147	            }
148	
149	            return null;
150	        } catch (RuntimeException $e) {
151	            $this->errorMessage = $e->getMessage();
152	            $this->myLock = null;
153	            $this->refreshAvailability();
154	            return null;
155	        }
156	    }
157	
158	    public function getAvailabilityPercentProperty(): float
159	    {
160	        if ($this->totalCapacity === 0) {
161	            return 0;
162	        }
163	
164	        return ($this->availableSeats / $this->totalCapacity) * 100;
165	    }
166	
167	    public function render(): View
168	    {
169	        return view('livewire.booking.seat-map');
170	    }
171	}
