3	namespace App\Http\Controllers\Api\Campaign;
4	
5	use App\Enums\CampaignStatus;
6	use App\Enums\CampaignVisibility;
7	use App\Http\Controllers\Api\BaseController;
8	use App\Models\BusinessParameter;
9	use App\Models\Campaign;
10	use App\Services\Campaign\CampaignLifecycleService;
11	use Illuminate\Http\JsonResponse;
12	use Illuminate\Http\Request;
13	use Illuminate\Support\Str;
14	use RuntimeException;
15	
16	class CampaignController extends BaseController
17	{
18	    public function __construct(
19	        private readonly CampaignLifecycleService $lifecycleService,
20	    ) {}
21	
22	    /**
23	     * GET /api/campaigns
24	     */
25	    public function index(Request $request): JsonResponse
26	    {
27	        $query = Campaign::query()
28	            ->with(['creator', 'rewardTiers']);
29	
30	        // Public listing: only published (fundraising+) and online campaigns.
31	        if (! $request->user()?->hasRole('moderator') && ! $request->user()?->hasRole('admin')) {
32	            $query->whereIn('status', [
33	                CampaignStatus::Fundraising,
34	                CampaignStatus::Success,
35	            ])->where('visibility', CampaignVisibility::Online);
36	        }
37	
38	        if ($request->filled('status')) {
39	            $query->where('status', $request->query('status'));
40	        }
41	
42	        return $this->paginated($query->latest());
43	    }
44	
45	    /**
46	     * GET /api/campaigns/{campaign}
47	     */
48	    public function show(Request $request, Campaign $campaign): JsonResponse
49	    {
50	        // Public users can only view published (fundraising/success) + online campaigns
51	        $user = $request->user();
52	        $isPrivileged = $user && ($user->hasRole('moderator') || $user->hasRole('admin') || $user->id === $campaign->creator_id);
53	
54	        if (! $isPrivileged) {
55	            $publicStatuses = [CampaignStatus::Fundraising, CampaignStatus::Success];
56	            if (! in_array($campaign->status, $publicStatuses) || $campaign->visibility !== CampaignVisibility::Online) {
57	                return $this->error('Resource not found.', 404);
58	            }
59	        }
60	
61	        $campaign->load(['creator', 'rewardTiers']);
62	
63	        $fundingProgress = $campaign->target_amount > 0
64	            ? round(($campaign->pledged_amount / $campaign->target_amount) * 100, 2)
65	            : 0;
66	
67	        return $this->success([
68	            'campaign' => $campaign,
69	            'funding_progress' => $fundingProgress,
70	        ]);
71	    }
72	
73	    /**
74	     * POST /api/campaigns
75	     */
76	    public function store(Request $request): JsonResponse
77	    {
78	        $this->authorize('create', Campaign::class);
79	
80	        $minDuration = (int) (BusinessParameter::where('key', 'campaign_min_duration_days')->first()?->getTypedValue() ?? 7);
81	        $maxDuration = (int) (BusinessParameter::where('key', 'campaign_max_duration_days')->first()?->getTypedValue() ?? 60);
82	
83	        $request->validate([
84	            'title' => 'required|string|max:255',
85	            'description' => 'required|string',
86	            'risk_disclosure' => 'required|string',
87	            'target_amount' => 'required|integer|min:1',
88	            'duration_days' => "required|integer|min:{$minDuration}|max:{$maxDuration}",
89	            'currency' => 'sometimes|string|max:3',
90	            'reward_tiers' => 'sometimes|array',
91	            'reward_tiers.*.title' => 'required_with:reward_tiers|string|max:255',
92	            'reward_tiers.*.price' => 'required_with:reward_tiers|integer|min:0',
93	            'reward_tiers.*.quantity_total' => 'sometimes|integer|min:0',
94	            'reward_tiers.*.fulfillment_type' => 'required_with:reward_tiers|string|in:digital,physical,event',
95	            'reward_tiers.*.sort_order' => 'sometimes|integer|min:0',
96	        ]);
97	
98	        $campaign = Campaign::create([
99	            'creator_id' => $request->user()->id,
100	            'title' => $request->input('title'),
101	            'slug' => Str::slug($request->input('title')) . '-' . Str::random(6),
102	            'description' => $request->input('description'),
103	            'risk_disclosure' => $request->input('risk_disclosure'),
104	            'target_amount' => $request->input('target_amount'),
105	            'pledged_amount' => 0,
106	            'currency' => $request->input('currency', 'USD'),
107	            'duration_days' => $request->input('duration_days'),
108	            'status' => CampaignStatus::Draft,
109	            'visibility' => CampaignVisibility::Offline,
110	        ]);
111	
112	        // Create reward tiers if provided
113	        if ($request->filled('reward_tiers')) {
114	            foreach ($request->input('reward_tiers') as $tier) {
115	                $campaign->rewardTiers()->create([
116	                    'title' => $tier['title'],
117	                    'description' => $tier['description'] ?? '',
118	                    'price' => $tier['price'],
119	                    'quantity_total' => $tier['quantity_total'] ?? 0,
120	                    'quantity_claimed' => 0,
121	                    'fulfillment_type' => $tier['fulfillment_type'],
122	                    'sort_order' => $tier['sort_order'] ?? 0,
123	                ]);
124	            }
125	        }
126	
127	        $campaign->load('rewardTiers');
128	
129	        return $this->success($campaign, 201);
130	    }
131	
132	    /**
133	     * PUT /api/campaigns/{campaign}
134	     */
135	    public function update(Request $request, Campaign $campaign): JsonResponse
136	    {
137	        $this->authorize('update', $campaign);
138	
139	        $minDuration = (int) (BusinessParameter::where('key', 'campaign_min_duration_days')->first()?->getTypedValue() ?? 7);
140	        $maxDuration = (int) (BusinessParameter::where('key', 'campaign_max_duration_days')->first()?->getTypedValue() ?? 60);
141	
142	        $request->validate([
143	            'title' => 'sometimes|string|max:255',
144	            'description' => 'sometimes|string',
145	            'risk_disclosure' => 'sometimes|string',
146	            'target_amount' => 'sometimes|integer|min:1',
147	            'duration_days' => "sometimes|integer|min:{$minDuration}|max:{$maxDuration}",
148	            'reward_tiers' => 'sometimes|array',
149	            'reward_tiers.*.title' => 'required_with:reward_tiers|string|max:255',
150	            'reward_tiers.*.price' => 'required_with:reward_tiers|integer|min:0',
151	            'reward_tiers.*.quantity_total' => 'sometimes|integer|min:0',
152	            'reward_tiers.*.fulfillment_type' => 'required_with:reward_tiers|string|in:digital,physical,event',
153	            'reward_tiers.*.sort_order' => 'sometimes|integer|min:0',
154	        ]);
155	
156	        $campaign->update($request->only([
157	            'title', 'description', 'risk_disclosure', 'target_amount', 'duration_days',
158	        ]));
159	
160	        // Replace reward tiers if provided
161	        if ($request->has('reward_tiers')) {
162	            $campaign->rewardTiers()->delete();
163	            foreach ($request->input('reward_tiers') as $tier) {
164	                $campaign->rewardTiers()->create([
165	                    'title' => $tier['title'],
166	                    'description' => $tier['description'] ?? '',
167	                    'price' => $tier['price'],
168	                    'quantity_total' => $tier['quantity_total'] ?? 0,
169	                    'quantity_claimed' => 0,
170	                    'fulfillment_type' => $tier['fulfillment_type'],
171	                    'sort_order' => $tier['sort_order'] ?? 0,
172	                ]);
173	            }
174	        }
175	
176	        return $this->success($campaign->refresh()->load('rewardTiers'));
177	    }
178	
179	    /**
180	     * POST /api/campaigns/{campaign}/submit
181	     */
182	    public function submit(Request $request, Campaign $campaign): JsonResponse
183	    {
184	        $this->authorize('submit', $campaign);
185	
186	        try {
187	            $campaign = $this->lifecycleService->submitForReview($campaign);
188	        } catch (RuntimeException $e) {
