188	    public function submitAfterSales(): void
189	    {
190	        $this->clearMessages();
191	
192	        $validTypes = ['refund', 'exchange', 'complaint', 'other'];
193	
194	        $this->validate([
195	            'afterSalesType' => 'required|string|in:' . implode(',', $validTypes),
196	            'afterSalesReason' => 'required|string|min:3|max:2000',
197	            'afterSalesAttachment' => 'required|file|max:10240|mimes:jpg,jpeg,png,pdf,doc,docx',
198	        ]);
199	
200	        try {
201	            $checksum = hash_file('sha256', $this->afterSalesAttachment->getRealPath());
202	
203	            $this->apiClient->postWithFile(
204	                "/api/orders/{$this->orderId}/after-sales",
205	                [
206	                    'type' => $this->afterSalesType,
207	                    'reason' => $this->afterSalesReason,
208	                    'client_checksum' => $checksum,
209	                ],
210	                'attachment',
211	                $this->afterSalesAttachment
212	            );
213	
214	            $this->successMessage = 'After-sales request submitted.';
215	            $this->showAfterSalesModal = false;
216	            $this->afterSalesType = '';
217	            $this->afterSalesReason = '';
218	            $this->afterSalesAttachment = null;
219	            $this->loadOrder();
220	        } catch (RuntimeException $e) {
221	            $this->errorMessage = $e->getMessage();
222	        }
223	    }
