258	    // --- Staff: Record Payment ------------------------------------------------
259	
260	    public function recordPayment(): void
261	    {
262	        $this->clearMessages();
263	
264	        $validMethods = ['cash', 'card_on_file'];
265	
266	        $this->validate([
267	            'paymentMethod' => 'required|string|in:' . implode(',', $validMethods),
268	            'paymentAmount' => 'required|integer|min:1',
269	            'transactionRef' => 'nullable|string|max:255',
270	        ]);
271	
272	        try {
273	            $this->apiClient->post("/api/orders/{$this->orderId}/payments", [
274	                'method' => $this->paymentMethod,
275	                'amount' => $this->paymentAmount,
276	                'transaction_ref' => $this->transactionRef ?: null,
277	            ]);
278	            $this->successMessage = 'Payment recorded successfully.';
279	            $this->transactionRef = '';
280	            $this->loadOrder();
281	        } catch (RuntimeException $e) {
282	            $this->errorMessage = $e->getMessage();
283	        }
284	    }
