287	
288	    public function markAttended(bool $attended): void
289	    {
290	        $this->clearMessages();
291	
292	        try {
293	            $this->apiClient->post("/api/orders/{$this->orderId}/attend", [
294	                'attended' => $attended,
295	            ]);
296	            $this->successMessage = $attended ? 'Marked as attended.' : 'Marked as not attended.';
297	            $this->loadOrder();
298	        } catch (RuntimeException $e) {
299	            $this->errorMessage = $e->getMessage();
300	        }
301	    }
