303	    // --- Helpers --------------------------------------------------------------
304	
305	    public function getIsStaffProperty(): bool
306	    {
307	        $user = Auth::user();
308	
309	        return $user && $user->hasRole('staff', 'moderator', 'admin');
310	    }
311	
312	    public function getIsPaidProperty(): bool
313	    {
314	        $payments = $this->order['payments'] ?? [];
315	
316	        foreach ($payments as $payment) {
317	            if (($payment['status'] ?? '') === 'completed') {
318	                return true;
319	            }
320	        }
321	
322	        return false;
323	    }
324	
325	    public function getCanRequestAfterSalesProperty(): bool
326	    {
327	        return ($this->order['status'] ?? '') === 'fulfilled'
328	            && !($this->order['has_pending_after_sales'] ?? false);
329	    }
330	
331	    private function clearMessages(): void
332	    {
333	        $this->errorMessage = '';
334	        $this->successMessage = '';
335	    }
336	
337	    public function render(): View
338	    {
339	        $paymentMethods = ['cash', 'card_on_file'];
340	        $afterSalesTypes = ['refund', 'exchange', 'complaint', 'other'];
341	
342	        return view('livewire.order.order-detail', [
343	            'isStaff' => $this->isStaff,
344	            'isPaid' => $this->isPaid,
345	            'canRequestAfterSales' => $this->canRequestAfterSales,
346	            'paymentMethods' => $paymentMethods,
347	            'afterSalesTypes' => $afterSalesTypes,
348	        ]);
349	    }
350	}
