87	test('POST /api/seat-locks/{id}/confirm is idempotent with same request key', function () {
88	    $lock = SeatLock::create([
89	        'time_slot_id' => $this->timeSlot->id,
90	        'user_id' => $this->user->id,
91	        'quantity' => 1,
