3	namespace App\Services;
4	
5	use Illuminate\Support\Facades\Http;
6	use Illuminate\Support\Facades\Session;
7	use Illuminate\Support\Str;
8	use Illuminate\Http\Client\Response;
9	use RuntimeException;
10	
11	class ApiClient
12	{
13	    private string $baseUrl;
14	
15	    public function __construct()
16	    {
17	        $this->baseUrl = rtrim(config('services.backend.url', 'http://backend-nginx:80'), '/');
18	    }
19	
20	    public function get(string $path, array $query = []): array
21	    {
22	        $response = $this->request()->get($this->baseUrl . $path, $query);
23	        return $this->handleResponse($response);
24	    }
25	
26	    public function post(string $path, array $data = [], array $headers = []): array
27	    {
28	        $request = $this->request();
29	        $headers = array_merge(['X-Idempotency-Key' => (string) Str::uuid()], $headers);
30	        $request = $request->withHeaders($headers);
31	        $response = $request->post($this->baseUrl . $path, $data);
32	        return $this->handleResponse($response);
33	    }
34	
35	    public function put(string $path, array $data = []): array
36	    {
37	        $response = $this->request()->put($this->baseUrl . $path, $data);
38	        return $this->handleResponse($response);
39	    }
40	
41	    public function delete(string $path): array
42	    {
43	        $response = $this->request()->delete($this->baseUrl . $path);
44	        return $this->handleResponse($response);
45	    }
46	
47	    public function postWithFile(string $path, array $data = [], string $fileKey = 'attachment', $file = null): array
48	    {
49	        $request = $this->request()->withHeaders([
50	            'X-Idempotency-Key' => (string) Str::uuid(),
51	        ]);
52	
53	        if ($file) {
54	            $request = $request->attach(
55	                $fileKey,
56	                file_get_contents($file->getRealPath()),
57	                $file->getClientOriginalName()
58	            );
59	        }
60	
61	        $response = $request->post($this->baseUrl . $path, $data);
62	        return $this->handleResponse($response);
63	    }
64	
65	    public function login(string $username, string $password): array
66	    {
67	        $response = Http::acceptJson()
68	            ->post($this->baseUrl . '/api/auth/login', [
69	                'username' => $username,
70	                'password' => $password,
71	            ]);
72	
73	        return $this->handleResponse($response);
74	    }
75	
76	    public function logout(): void
77	    {
78	        try {
79	            $this->post('/api/auth/logout');
80	        } catch (RuntimeException $e) {
81	            // Ignore logout errors
82	        }
83	    }
84	
85	    private function request(): \Illuminate\Http\Client\PendingRequest
86	    {
87	        $request = Http::acceptJson()->timeout(30);
88	        $token = Session::get('api_token');
89	        if ($token) {
90	            $request = $request->withToken($token);
91	        }
92	        return $request;
93	    }
94	
95	    private function handleResponse(Response $response): array
96	    {
97	        if ($response->successful()) {
98	            return $response->json() ?? [];
99	        }
100	
101	        if ($response->status() === 401) {
102	            Session::forget(['api_token', 'api_user']);
103	            throw new RuntimeException('Session expired. Please log in again.', 401);
104	        }
105	
106	        $body = $response->json();
107	        $message = $body['msg'] ?? $body['message'] ?? 'API request failed';
108	        throw new RuntimeException($message, $response->status());
109	    }
110	}
