6	use Illuminate\Database\Eloquent\Model;
7	use Illuminate\Database\Eloquent\Relations\BelongsTo;
8	
9	class CreditScore extends Model
10	{
11	    protected $fillable = [
12	        'user_id',
13	        'score',
14	        'no_show_count',
15	        'chargeback_count',
16	        'refund_count',
17	        'violation_count',
18	        'restriction_level',
19	        'restriction_until',
20	    ];
21	
22	    protected function casts(): array
23	    {
24	        return [
25	            'score' => 'integer',
26	            'no_show_count' => 'integer',
27	            'chargeback_count' => 'integer',
28	            'refund_count' => 'integer',
29	            'violation_count' => 'integer',
30	            'restriction_level' => RestrictionLevel::class,
31	            'restriction_until' => 'datetime',
32	        ];
33	    }
34	
35	    public function user(): BelongsTo
36	    {
37	        return $this->belongsTo(User::class);
38	    }
39	
40	    public function isBlacklisted(): bool
41	    {
42	        if ($this->restriction_level !== RestrictionLevel::Black) {
43	            return false;
44	        }
45	
46	        // Blacklist has a time limit — if restriction_until has passed, the restriction has expired
47	        if ($this->restriction_until && $this->restriction_until->isPast()) {
48	            return false;
49	        }
50	
51	        return true;
52	    }
53	
54	    public function isGraylisted(): bool
55	    {
56	        return $this->restriction_level === RestrictionLevel::Gray;
57	    }
58	
59	    public function isRestricted(): bool
60	    {
61	        return $this->isBlacklisted() || $this->isGraylisted();
62	    }
63	
64	    public function canPlaceOrders(): bool
