64	    public function canPlaceOrders(): bool
65	    {
66	        // Blacklisted users cannot place orders at all
67	        if ($this->isBlacklisted()) {
68	            return false;
69	        }
70	
71	        // Graylisted users can place orders but need staff approval (handled at booking level)
72	        // Only fully blocked (blacklisted) users are prevented here
73	        return true;
74	    }
75	
76	    public function requiresStaffApproval(): bool
77	    {
78	        return $this->isGraylisted();
79	    }
