3	namespace App\Services\Order;
4	
5	use App\Enums\OrderStatus;
6	use App\Enums\RefundStatus;
7	use App\Events\RefundApproved;
8	use App\Events\RefundRejected;
9	use App\Models\Order;
10	use App\Models\RefundRequest;
11	use App\Models\User;
12	
13	class RefundService
14	{
15	    public function submitRequest(Order $order, User $user, string $reason, int $amount): RefundRequest
16	    {
17	        if ($order->status !== OrderStatus::Fulfilled) {
18	            throw new \RuntimeException('Refunds can only be requested for fulfilled orders.');
19	        }
20	
21	        if ($order->refund_deadline && now()->isAfter($order->refund_deadline)) {
22	            throw new \RuntimeException('The refund window has expired.');
23	        }
24	
25	        if ($order->has_pending_after_sales) {
26	            throw new \RuntimeException('Cannot submit refund while an after-sales request is pending.');
27	        }
28	
29	        $refundRequest = RefundRequest::create([
30	            'order_id' => $order->id,
31	            'requested_by' => $user->id,
32	            'reason' => $reason,
33	            'status' => RefundStatus::Pending,
34	            'refund_amount' => $amount,
35	        ]);
36	
37	        $order->update(['has_pending_refund' => true]);
38	
39	        return $refundRequest;
40	    }
41	
42	    public function approve(RefundRequest $request, User $reviewer): RefundRequest
43	    {
44	        if ($request->status !== RefundStatus::Pending) {
45	            throw new \RuntimeException('Only pending refund requests can be approved.');
46	        }
47	
48	        $request->update([
49	            'status' => RefundStatus::Approved,
50	            'reviewed_by' => $reviewer->id,
51	            'reviewed_at' => now(),
52	        ]);
53	
54	        $order = $request->order;
55	        $order->update([
56	            'has_pending_refund' => false,
57	            'status' => OrderStatus::Refunded,
58	        ]);
59	
60	        $request->refresh();
61	        $order->refresh();
62	
63	        // Dispatch events after all DB writes are committed
64	        try {
65	            RefundApproved::dispatch($request, $reviewer);
66	            \App\Events\OrderRefunded::dispatch($order, $request);
67	        } catch (\Throwable $e) {
68	            report($e);
69	        }
70	
71	        return $request;
72	    }
73	
74	    public function reject(RefundRequest $request, User $reviewer): RefundRequest
75	    {
76	        if ($request->status !== RefundStatus::Pending) {
77	            throw new \RuntimeException('Only pending refund requests can be rejected.');
78	        }
79	
80	        $request->update([
81	            'status' => RefundStatus::Rejected,
82	            'reviewed_by' => $reviewer->id,
83	            'reviewed_at' => now(),
84	        ]);
85	
86	        $request->order->update(['has_pending_refund' => false]);
87	
88	        $request->refresh();
89	
90	        RefundRejected::dispatch($request, $reviewer);
91	
92	        return $request;
93	    }
94	}
