3	namespace App\Services\RiskControl;
4	
5	use App\Enums\AnomalyType;
6	use App\Models\AnomalyFlag;
7	use App\Models\DeviceFingerprint;
8	use App\Models\RefundRequest;
9	use App\Models\User;
10	use Illuminate\Support\Collection;
11	
12	class AnomalyDetectionService
13	{
14	    private const DEFAULT_REFUND_THRESHOLD = 3;
15	
16	    private const DEFAULT_REFUND_WINDOW_DAYS = 30;
17	
18	    public function checkRefundFrequency(User $user): ?AnomalyFlag
19	    {
20	        $windowDays = $this->getParameter('anomaly_refund_window_days', self::DEFAULT_REFUND_WINDOW_DAYS);
21	        $threshold = $this->getParameter('anomaly_refund_threshold', self::DEFAULT_REFUND_THRESHOLD);
22	
23	        $recentRefundCount = RefundRequest::query()
24	            ->where('requested_by', $user->id)
25	            ->where('created_at', '>=', now()->subDays($windowDays))
26	            ->count();
27	
28	        if ($recentRefundCount > $threshold) {
29	            return $this->flagAnomaly(
30	                $user,
31	                AnomalyType::ExcessiveRefunds,
32	                [
33	                    'refund_count' => $recentRefundCount,
34	                    'window_days' => $windowDays,
35	                    'threshold' => $threshold,
36	                ]
37	            );
38	        }
39	
40	        return null;
41	    }
42	
43	    public function detectDuplicateDevices(): Collection
44	    {
45	        $duplicates = DeviceFingerprint::query()
46	            ->select('fingerprint_hash')
47	            ->selectRaw('COUNT(DISTINCT user_id) as user_count')
48	            ->groupBy('fingerprint_hash')
49	            ->havingRaw('COUNT(DISTINCT user_id) > 1')
50	            ->get();
51	
52	        $flagged = collect();
53	
54	        foreach ($duplicates as $duplicate) {
55	            $userIds = DeviceFingerprint::query()
56	                ->where('fingerprint_hash', $duplicate->fingerprint_hash)
57	                ->distinct()
58	                ->pluck('user_id');
59	
60	            foreach ($userIds as $userId) {
61	                $existing = AnomalyFlag::query()
62	                    ->where('user_id', $userId)
63	                    ->where('type', AnomalyType::DuplicateDeviceFingerprint)
64	                    ->whereNull('resolved_at')
65	                    ->first();
66	
67	                if (! $existing) {
68	                    $user = User::find($userId);
69	
70	                    if ($user) {
71	                        $flag = $this->flagAnomaly(
72	                            $user,
73	                            AnomalyType::DuplicateDeviceFingerprint,
74	                            [
75	                                'fingerprint_hash' => $duplicate->fingerprint_hash,
76	                                'shared_user_ids' => $userIds->toArray(),
77	                            ]
78	                        );
79	                        $flagged->push($flag);
80	                    }
81	                }
82	            }
83	        }
84	
85	        return $flagged;
86	    }
87	
88	    private function getParameter(string $key, int $default): int
89	    {
90	        $param = \App\Models\BusinessParameter::where('key', $key)->first();
91	
92	        return $param ? (int) $param->getTypedValue() : $default;
93	    }
94	
95	    public function flagAnomaly(User $user, AnomalyType $type, array $evidence = []): AnomalyFlag
96	    {
97	        return AnomalyFlag::create([
98	            'user_id' => $user->id,
99	            'type' => $type,
100	            'description' => "Anomaly detected: {$type->value}",
101	            'evidence' => $evidence,
102	        ]);
103	    }
104	}
