42	    {
43	        $response = $this->request()->delete($this->baseUrl . $path);
44	        return $this->handleResponse($response);
45	    }
46	
47	    public function postWithFile(string $path, array $data = [], string $fileKey = 'attachment', $file = null, array $headers = []): array
48	    {
49	        $defaultHeaders = ['X-Idempotency-Key' => (string) Str::uuid()];
50	        $request = $this->request()->withHeaders(array_merge($defaultHeaders, $headers));
51	
52	        if ($file) {
53	            $request = $request->attach(
54	                $fileKey,
55	                file_get_contents($file->getRealPath()),
56	                $file->getClientOriginalName()
57	            );
58	        }
59	
60	        $response = $request->post($this->baseUrl . $path, $data);
61	        return $this->handleResponse($response);
62	    }
