80	            // Ignore logout errors
81	        }
82	    }
83	
84	    private function request(): \Illuminate\Http\Client\PendingRequest
85	    {
86	        $request = Http::acceptJson()->timeout(30);
87	        $token = Session::get('api_token');
88	        if ($token) {
89	            $request = $request->withToken($token);
90	        }
91	        return $request;
92	    }
