94	    private function handleResponse(Response $response): array
95	    {
96	        if ($response->successful()) {
97	            return $response->json() ?? [];
98	        }
99	
100	        if ($response->status() === 401) {
101	            Session::forget(['api_token', 'api_user']);
102	            throw new RuntimeException('Session expired. Please log in again.', 401);
103	        }
104	
105	        $body = $response->json();
106	        $message = $body['msg'] ?? $body['message'] ?? 'API request failed';
107	        throw new RuntimeException($message, $response->status());
