3	namespace App\Livewire\Booking;
4	
5	use App\Services\ApiClient;
6	use Illuminate\Contracts\View\View;
7	use Livewire\Attributes\Layout;
8	use Livewire\Component;
9	use RuntimeException;
10	
11	#[Layout('layouts.app')]
12	class SeatMap extends Component
13	{
14	    protected ApiClient $apiClient;
15	
16	    public int $timeSlotId;
17	    public array $timeSlot = [];
18	    public int $availableSeats = 0;
19	    public int $totalCapacity = 0;
20	    public int $seatsBooked = 0;
21	    public int $lockedByOthers = 0;
22	    public ?array $myLock = null;
23	    public int $quantity = 1;
24	    public string $confirmationNumber = '';
25	    public string $errorMessage = '';
26	    public string $lockKey = '';
27	
28	    public function boot(ApiClient $apiClient): void
29	    {
30	        $this->apiClient = $apiClient;
31	    }
32	
33	    public function mount(int $timeSlotId): void
34	    {
35	        $this->timeSlotId = $timeSlotId;
36	        $this->refreshAvailability();
37	    }
38	
39	    public function refreshAvailability(): void
40	    {
41	        try {
42	            $response = $this->apiClient->get("/api/time-slots/{$this->timeSlotId}");
43	
44	            $this->timeSlot = $response['time_slot'] ?? [];
45	            $this->availableSeats = $response['available_seats'] ?? 0;
46	            $this->totalCapacity = $this->timeSlot['seat_capacity'] ?? 0;
47	            $this->seatsBooked = $this->timeSlot['seats_booked'] ?? 0;
48	
49	            $locks = $response['locks'] ?? [];
50	
51	            // Calculate locks by others and check for my lock
52	            $this->lockedByOthers = 0;
53	            $foundMyLock = false;
54	
55	            foreach ($locks as $lock) {
56	                if (!empty($lock['held_by_me'])) {
57	                    $this->myLock = [
58	                        'id' => $lock['id'],
59	                        'quantity' => $lock['quantity'],
60	                        'locked_until' => $lock['locked_until'],
61	                    ];
62	                    $foundMyLock = true;
63	                } elseif (!empty($lock['held_by_other'])) {
64	                    $this->lockedByOthers += $lock['quantity'];
65	                }
66	            }
67	
68	            // If we had a lock but it's no longer in the active list, clear it
69	            if ($this->myLock && !$foundMyLock) {
70	                $this->myLock = null;
71	            }
72	        } catch (RuntimeException $e) {
73	            $this->errorMessage = $e->getMessage();
74	        }
75	    }
76	
77	    public function lockSeats(): void
78	    {
79	        $this->errorMessage = '';
80	
81	        if ($this->quantity < 1) {
82	            $this->errorMessage = 'Quantity must be at least 1.';
83	            return;
84	        }
85	
86	        if ($this->lockKey === '') {
87	            $this->lockKey = 'lock-' . $this->timeSlotId . '-' . uniqid();
88	        }
89	
90	        try {
91	            $response = $this->apiClient->post("/api/time-slots/{$this->timeSlotId}/lock", [
92	                'quantity' => $this->quantity,
93	            ], ['X-Idempotency-Key' => $this->lockKey]);
94	
95	            $this->lockKey = '';
96	
97	            $lock = $response['lock'] ?? [];
98	            $this->myLock = [
99	                'id' => $lock['id'],
100	                'quantity' => $lock['quantity'],
101	                'locked_until' => $lock['locked_until'],
102	            ];
103	
104	            $this->refreshAvailability();
105	        } catch (RuntimeException $e) {
106	            $this->errorMessage = $e->getMessage();
107	        }
108	    }
109	
110	    public function releaseLock(): void
111	    {
112	        $this->errorMessage = '';
113	
114	        if (!$this->myLock) {
115	            return;
116	        }
117	
118	        try {
119	            $lockId = $this->myLock['id'];
120	            $this->apiClient->delete("/api/seat-locks/{$lockId}");
121	        } catch (RuntimeException $e) {
122	            // Lock may have already expired
123	        }
124	
125	        $this->myLock = null;
126	        $this->refreshAvailability();
127	    }
128	
129	    public function confirmBooking(): mixed
130	    {
131	        $this->errorMessage = '';
132	
133	        if (!$this->myLock) {
134	            $this->errorMessage = 'You must lock seats before confirming.';
135	            return null;
136	        }
137	
138	        try {
139	            $lockId = $this->myLock['id'];
140	            $idempotencyKey = 'confirm-' . $lockId . '-' . session()->getId();
141	            $response = $this->apiClient->post("/api/seat-locks/{$lockId}/confirm", [], [
142	                'X-Idempotency-Key' => $idempotencyKey,
143	            ]);
144	
145	            $this->confirmationNumber = $response['confirmation_number'] ?? '';
146	            $orderId = $response['order']['id'] ?? null;
147	            $this->myLock = null;
148	
149	            if ($orderId) {
150	                return $this->redirect(
151	                    route('orders.detail', ['orderId' => $orderId]),
152	                    navigate: true,
153	                );
154	            }
155	
156	            return null;
157	        } catch (RuntimeException $e) {
158	            $this->errorMessage = $e->getMessage();
159	            $this->myLock = null;
160	            $this->refreshAvailability();
161	            return null;
162	        }
163	    }
164	
165	    public function getAvailabilityPercentProperty(): float
166	    {
167	        if ($this->totalCapacity === 0) {
168	            return 0;
169	        }
170	
171	        return ($this->availableSeats / $this->totalCapacity) * 100;
172	    }
173	
174	    public function render(): View
175	    {
176	        return view('livewire.booking.seat-map');
177	    }
178	}
