3	namespace App\Livewire\Review;
4	
5	use App\Services\ApiClient;
6	use Illuminate\Contracts\View\View;
7	use Illuminate\Support\Facades\Auth;
8	use Livewire\Attributes\Layout;
9	use Livewire\Component;
10	use RuntimeException;
11	
12	#[Layout('layouts.app')]
13	class ReviewForm extends Component
14	{
15	    protected ApiClient $apiClient;
16	
17	    public int $orderId = 0;
18	
19	    public string $side = 'user_to_creator';
20	
21	    public int $overallRating = 0;
22	
23	    public string $body = '';
24	
25	    public array $dimensions = [
26	        'communication' => 0,
27	        'accuracy' => 0,
28	        'value' => 0,
29	    ];
30	
31	    public array $tags = [];
32	
33	    public bool $submitted = false;
34	
35	    public string $errorMessage = '';
36	
37	    public array $order = [];
38	
39	    public function boot(ApiClient $apiClient): void
40	    {
41	        $this->apiClient = $apiClient;
42	    }
43	
44	    public function mount(int $orderId): void
45	    {
46	        $this->orderId = $orderId;
47	
48	        $response = $this->apiClient->get("/api/orders/{$orderId}");
49	
50	        // Unwrap if wrapped in 'data'
51	        if (isset($response['data']) && !isset($response['id'])) {
52	            $this->order = $response['data'];
53	        } else {
54	            $this->order = $response;
55	        }
56	
57	        if (($this->order['status'] ?? '') !== 'fulfilled') {
58	            abort(403, 'Reviews can only be submitted for fulfilled orders.');
59	        }
60	
61	        $user = Auth::user();
62	
63	        // Determine default side: if current user is the campaign creator, they review the buyer
64	        if (!empty($this->order['campaign']) && $user && $user->id === ($this->order['campaign']['creator_id'] ?? null)) {
65	            $this->side = 'creator_to_user';
66	        } else {
67	            $this->side = 'user_to_creator';
68	        }
69	    }
70	
71	    public function setOverallRating(int $rating): void
72	    {
73	        $this->overallRating = $rating;
74	    }
75	
76	    public function setDimensionRating(string $dimension, int $rating): void
77	    {
78	        if (array_key_exists($dimension, $this->dimensions)) {
79	            $this->dimensions[$dimension] = $rating;
80	        }
81	    }
82	
83	    public function toggleTag(string $tag): void
84	    {
85	        if (in_array($tag, $this->tags)) {
86	            $this->tags = array_values(array_diff($this->tags, [$tag]));
87	        } else {
88	            $this->tags[] = $tag;
89	        }
90	    }
91	
92	    public function submit(): void
93	    {
94	        $this->errorMessage = '';
95	
96	        $this->validate([
97	            'overallRating' => 'required|integer|min:1|max:5',
98	            'body' => 'nullable|string|max:2000',
99	            'side' => 'required|in:user_to_creator,creator_to_user',
100	        ]);
101	
102	        try {
103	            $dimensions = [];
104	            foreach ($this->dimensions as $name => $rating) {
105	                if ($rating > 0) {
106	                    $dimensions[] = ['dimension' => $name, 'rating' => (int) $rating];
107	                }
108	            }
109	
110	            $scope = "idempotency:review:{$this->orderId}";
111	            $key = session($scope);
112	            if (! $key) {
113	                $key = 'review-' . $this->orderId . '-' . uniqid();
114	                session()->put($scope, $key);
115	            }
116	
117	            $this->apiClient->post("/api/orders/{$this->orderId}/reviews", [
118	                'side' => $this->side,
119	                'overall_rating' => $this->overallRating,
120	                'body' => $this->body,
121	                'dimensions' => $dimensions,
122	                'tags' => $this->tags,
123	            ], ['X-Idempotency-Key' => $key]);
124	
125	            session()->forget($scope);
126	            $this->submitted = true;
127	        } catch (RuntimeException $e) {
128	            $this->errorMessage = $e->getMessage();
129	        }
130	    }
131	
132	    public function render(): View
133	    {
134	        $availableTags = ['friendly', 'late_delivery', 'as_described', 'great_value'];
135	
136	        return view('livewire.review.review-form', [
137	            'availableTags' => $availableTags,
138	        ]);
139	    }
140	}
