10	
11	#[Layout('layouts.app')]
12	class SeatMap extends Component
13	{
14	    protected ApiClient $apiClient;
15	
16	    public int $timeSlotId;
17	    public array $timeSlot = [];
18	    public int $availableSeats = 0;
19	    public int $totalCapacity = 0;
20	    public int $seatsBooked = 0;
21	    public int $lockedByOthers = 0;
22	    public ?array $myLock = null;
23	    public int $quantity = 1;
24	    public string $confirmationNumber = '';
25	    public string $errorMessage = '';
26	
27	    public function boot(ApiClient $apiClient): void
28	    {
29	        $this->apiClient = $apiClient;
30	    }
31	
32	    public function mount(int $timeSlotId): void
33	    {
34	        $this->timeSlotId = $timeSlotId;
35	        $this->refreshAvailability();
36	    }
37	
38	    public function refreshAvailability(): void
39	    {
40	        try {
41	            $response = $this->apiClient->get("/api/time-slots/{$this->timeSlotId}");
42	
43	            $this->timeSlot = $response['time_slot'] ?? [];
44	            $this->availableSeats = $response['available_seats'] ?? 0;
45	            $this->totalCapacity = $this->timeSlot['seat_capacity'] ?? 0;
46	            $this->seatsBooked = $this->timeSlot['seats_booked'] ?? 0;
47	
48	            $locks = $response['locks'] ?? [];
49	
50	            // Calculate locks by others and check for my lock
51	            $this->lockedByOthers = 0;
52	            $foundMyLock = false;
53	
54	            foreach ($locks as $lock) {
55	                if (!empty($lock['held_by_me'])) {
56	                    $this->myLock = [
57	                        'id' => $lock['id'],
58	                        'quantity' => $lock['quantity'],
59	                        'locked_until' => $lock['locked_until'],
60	                    ];
61	                    $foundMyLock = true;
62	                } elseif (!empty($lock['held_by_other'])) {
63	                    $this->lockedByOthers += $lock['quantity'];
64	                }
65	            }
66	
67	            // If we had a lock but it's no longer in the active list, clear it
68	            if ($this->myLock && !$foundMyLock) {
69	                $this->myLock = null;
70	            }
71	        } catch (RuntimeException $e) {
72	            $this->errorMessage = $e->getMessage();
73	        }
74	    }
75	
76	    public function lockSeats(): void
77	    {
78	        $this->errorMessage = '';
79	
80	        if ($this->quantity < 1) {
81	            $this->errorMessage = 'Quantity must be at least 1.';
82	            return;
83	        }
84	
85	        $scope = "idempotency:lock:{$this->timeSlotId}";
86	        $key = session($scope);
87	        if (! $key) {
88	            $key = 'lock-' . $this->timeSlotId . '-' . uniqid();
89	            session()->put($scope, $key);
90	        }
91	
92	        try {
93	            $response = $this->apiClient->post("/api/time-slots/{$this->timeSlotId}/lock", [
94	                'quantity' => $this->quantity,
95	            ], ['X-Idempotency-Key' => $key]);
96	
97	            session()->forget($scope);
98	
99	            $lock = $response['lock'] ?? [];
100	            $this->myLock = [
101	                'id' => $lock['id'],
102	                'quantity' => $lock['quantity'],
103	                'locked_until' => $lock['locked_until'],
104	            ];
105	
106	            $this->refreshAvailability();
107	        } catch (RuntimeException $e) {
108	            $this->errorMessage = $e->getMessage();
109	        }
110	    }
111	
112	    public function releaseLock(): void
113	    {
114	        $this->errorMessage = '';
115	
116	        if (!$this->myLock) {
117	            return;
118	        }
119	
120	        try {
121	            $lockId = $this->myLock['id'];
122	            $this->apiClient->delete("/api/seat-locks/{$lockId}");
123	        } catch (RuntimeException $e) {
124	            // Lock may have already expired
125	        }
126	
127	        $this->myLock = null;
128	        $this->refreshAvailability();
129	    }
130	
131	    public function confirmBooking(): mixed
132	    {
133	        $this->errorMessage = '';
134	
135	        if (!$this->myLock) {
136	            $this->errorMessage = 'You must lock seats before confirming.';
137	            return null;
138	        }
139	
140	        try {
141	            $lockId = $this->myLock['id'];
142	            $idempotencyKey = 'confirm-' . $lockId . '-' . session()->getId();
143	            $response = $this->apiClient->post("/api/seat-locks/{$lockId}/confirm", [], [
144	                'X-Idempotency-Key' => $idempotencyKey,
145	            ]);
146	
147	            $this->confirmationNumber = $response['confirmation_number'] ?? '';
148	            $orderId = $response['order']['id'] ?? null;
149	            $this->myLock = null;
150	
151	            if ($orderId) {
152	                return $this->redirect(
153	                    route('orders.detail', ['orderId' => $orderId]),
154	                    navigate: true,
155	                );
156	            }
157	
158	            return null;
159	        } catch (RuntimeException $e) {
160	            $this->errorMessage = $e->getMessage();
161	            $this->myLock = null;
162	            $this->refreshAvailability();
163	            return null;
164	        }
165	    }
166	
167	    public function getAvailabilityPercentProperty(): float
168	    {
169	        if ($this->totalCapacity === 0) {
170	            return 0;
171	        }
172	
173	        return ($this->availableSeats / $this->totalCapacity) * 100;
174	    }
175	
176	    public function render(): View
177	    {
178	        return view('livewire.booking.seat-map');
179	    }
180	}
