3	namespace App\Services;
4	
5	use Illuminate\Support\Facades\Http;
6	use Illuminate\Support\Facades\Session;
7	use Illuminate\Http\Client\Response;
8	use RuntimeException;
9	
10	class ApiClient
11	{
12	    private string $baseUrl;
13	
14	    public function __construct()
15	    {
16	        $this->baseUrl = rtrim(config('services.backend.url', 'http://backend-nginx:80'), '/');
17	    }
18	
19	    public function get(string $path, array $query = []): array
20	    {
21	        $response = $this->request()->get($this->baseUrl . $path, $query);
22	        return $this->handleResponse($response);
23	    }
24	
25	    public function post(string $path, array $data = [], array $headers = []): array
26	    {
27	        $request = $this->request();
28	        if (!empty($headers)) {
29	            $request = $request->withHeaders($headers);
30	        }
31	        $response = $request->post($this->baseUrl . $path, $data);
32	        return $this->handleResponse($response);
33	    }
34	
35	    public function put(string $path, array $data = []): array
36	    {
37	        $response = $this->request()->put($this->baseUrl . $path, $data);
38	        return $this->handleResponse($response);
39	    }
40	
41	    public function delete(string $path): array
42	    {
43	        $response = $this->request()->delete($this->baseUrl . $path);
44	        return $this->handleResponse($response);
45	    }
46	
47	    public function postWithFile(string $path, array $data = [], string $fileKey = 'attachment', $file = null, array $headers = []): array
48	    {
49	        $request = $this->request();
50	        if (!empty($headers)) {
51	            $request = $request->withHeaders($headers);
52	        }
53	
54	        if ($file) {
55	            $request = $request->attach(
56	                $fileKey,
57	                file_get_contents($file->getRealPath()),
58	                $file->getClientOriginalName()
59	            );
60	        }
61	
62	        $response = $request->post($this->baseUrl . $path, $data);
63	        return $this->handleResponse($response);
64	    }
65	
66	    public function login(string $username, string $password): array
67	    {
68	        $response = Http::acceptJson()
69	            ->post($this->baseUrl . '/api/auth/login', [
70	                'username' => $username,
71	                'password' => $password,
72	            ]);
73	
74	        return $this->handleResponse($response);
75	    }
76	
77	    public function logout(): void
78	    {
79	        try {
80	            $this->post('/api/auth/logout');
81	        } catch (RuntimeException $e) {
82	            // Ignore logout errors
83	        }
84	    }
85	
86	    private function request(): \Illuminate\Http\Client\PendingRequest
87	    {
88	        $request = Http::acceptJson()->timeout(30);
89	        $token = Session::get('api_token');
90	        if ($token) {
91	            $request = $request->withToken($token);
92	        }
93	        return $request;
94	    }
95	
96	    private function handleResponse(Response $response): array
97	    {
98	        if ($response->successful()) {
99	            return $response->json() ?? [];
100	        }
101	
102	        if ($response->status() === 401) {
103	            Session::forget(['api_token', 'api_user']);
104	            throw new RuntimeException('Session expired. Please log in again.', 401);
105	        }
106	
107	        $body = $response->json();
108	        $message = $body['msg'] ?? $body['message'] ?? 'API request failed';
109	        throw new RuntimeException($message, $response->status());
110	    }
111	}
