124	            // Lock may have already expired
125	        }
126	
127	        $this->myLock = null;
128	        $this->refreshAvailability();
129	    }
130	
131	    public function confirmBooking(): mixed
132	    {
133	        $this->errorMessage = '';
134	
135	        if (!$this->myLock) {
136	            $this->errorMessage = 'You must lock seats before confirming.';
137	            return null;
138	        }
139	
140	        try {
141	            $lockId = $this->myLock['id'];
142	            $idempotencyKey = 'confirm-' . $lockId . '-' . session()->getId();
143	            $response = $this->apiClient->post("/api/seat-locks/{$lockId}/confirm", [], [
144	                'X-Idempotency-Key' => $idempotencyKey,
145	            ]);
146	
147	            $this->confirmationNumber = $response['confirmation_number'] ?? '';
148	            $orderId = $response['order']['id'] ?? null;
149	            $this->myLock = null;
150	
151	            if ($orderId) {
152	                return $this->redirect(
153	                    route('orders.detail', ['orderId' => $orderId]),
154	                    navigate: true,
155	                );
156	            }
157	
158	            return null;
159	        } catch (RuntimeException $e) {
160	            $this->errorMessage = $e->getMessage();
161	            $this->myLock = null;
162	            $this->refreshAvailability();
163	            return null;
164	        }
165	    }
166	
167	    public function getAvailabilityPercentProperty(): float
168	    {
169	        if ($this->totalCapacity === 0) {
170	            return 0;
171	        }
172	
173	        return ($this->availableSeats / $this->totalCapacity) * 100;
174	    }
