39	    public function boot(ApiClient $apiClient): void
40	    {
41	        $this->apiClient = $apiClient;
42	    }
43	
44	    public function mount(int $orderId): void
45	    {
46	        $this->orderId = $orderId;
47	
48	        $response = $this->apiClient->get("/api/orders/{$orderId}");
49	
50	        // Unwrap if wrapped in 'data'
51	        if (isset($response['data']) && !isset($response['id'])) {
52	            $this->order = $response['data'];
53	        } else {
54	            $this->order = $response;
55	        }
56	
57	        if (($this->order['status'] ?? '') !== 'fulfilled') {
58	            abort(403, 'Reviews can only be submitted for fulfilled orders.');
59	        }
60	
61	        $user = Auth::user();
62	
63	        // Determine default side: if current user is the campaign creator, they review the buyer
64	        if (!empty($this->order['campaign']) && $user && $user->id === ($this->order['campaign']['creator_id'] ?? null)) {
65	            $this->side = 'creator_to_user';
66	        } else {
67	            $this->side = 'user_to_creator';
